            int exitCode = process.waitFor();

            // Process results
            String output = result.toString().trim();
            if (exitCode != 0 && output.isEmpty()) {
                return "Error: Search command failed with exit code " + exitCode;
            }

            return output.isEmpty() ? "No files found matching the pattern" : output;

        } catch (IOException e) {
            return "Error: Failed to execute search command - " + e.getMessage();
        } catch (InterruptedException e) {
            Thread.currentThread().interrupt();
            return "Error: Search operation was interrupted";
        }
    }

    /**
     * Validates input parameters for security and correctness.
     * Prevents command injection by restricting allowed characters.
     * 
     * @param searchDir   The directory path to validate
     * @param filePattern The file pattern to validate
     * @return An error message if validation fails, null if validation passes
     */
    private String validateInputs(String searchDir, String filePattern) {
        // Check for null or empty directory
        if (searchDir == null || searchDir.trim().isEmpty()) {
            return "Error: Search directory cannot be null or empty";
        }

        // Check for null or empty pattern
        if (filePattern == null || filePattern.trim().isEmpty()) {
            return "Error: File pattern cannot be null or empty";
        }

        // Security: Validate directory path contains only safe characters
        // This prevents command injection attacks
        if (!SAFE_DIR_PATTERN.matcher(searchDir.trim()).matches()) {
            return "Error: Invalid directory path - contains disallowed characters";
        }

        // Security: Validate file pattern contains only safe characters
        // This prevents command injection attacks
        if (!SAFE_FILE_PATTERN.matcher(filePattern.trim()).matches()) {
            return "Error: Invalid file pattern - contains disallowed characters";
        }

        // Verify the directory exists and is accessible
        File dir = new File(searchDir.trim());
        if (!dir.exists()) {
            return "Error: Directory does not exist: " + searchDir;
        }

        if (!dir.isDirectory()) {
            return "Error: Path is not a directory: " + searchDir;
        }

        if (!dir.canRead()) {
            return "Error: Cannot read directory: " + searchDir;
        }

        return null;
    }

    /**
     * Escapes a string for safe use in a shell command.
     * Wraps the input in single quotes and escapes any single quotes within.
     * Single quotes prevent all shell expansion and interpretation.
     * 
     * @param input The string to escape
     * @return The escaped string safely wrapped in single quotes
     */
    private String escapeForShell(String input) {
        // Single quotes prevent shell expansion
        // Any single quote in input is escaped using '\'' pattern
        return "'" + input.replace("'", "'\\''") + "'";
    }
}
